/// Lower `apply(model_ident, X)` onto the autograd tape by walking
/// the stored `ModelSpec` and threading the input tensor through each
/// layer as a composition of primitive tape ops. This is what makes
/// `grad(loss_with_apply, W)` and `adam(loss_with_apply, mdl, ...)`
/// work: the model's forward pass becomes a regular tape subgraph
/// rooted at the leaf tensors for each layer's trainable parameters.
fn eval_tensor_apply(
    model_arg: &Expr,
    x_arg: &Expr,
    env: &mut Environment,
    tape: &Rc<Tape>,
    params: &HashMap<String, Tensor>,
) -> Result<Tensor, EvalError> {
    let model_name = match model_arg {
        Expr::Ident(n, _) => n.clone(),
        _ => {
            return Err(EvalError::Unsupported(
                "grad: apply's first argument must be a model identifier".into(),
            ));
        }
    };
    let model = env
        .get_model(&model_name)
        .cloned()
        .ok_or_else(|| EvalError::UndefinedVariable(model_name))?;
    let x = eval_tensor_expr(x_arg, env, tape, params)?;
    apply_model_tape(&model, x, tape, params)
}

/// Tape-side analogue of `model_dispatch::apply_model`. Emits the same
/// primitive ops onto the autograd tape so gradients flow back to each
/// layer's trainable parameter leaves. Layers without primitive tape
/// equivalents are reported as unsupported for now; teaching them here
/// is a follow-up task (tracked for the transformer-block demo).
fn apply_model_tape(
    model: &ModelSpec,
    x: Tensor,
    tape: &Rc<Tape>,
    params: &HashMap<String, Tensor>,
) -> Result<Tensor, EvalError> {
    match model {
        ModelSpec::Linear { w, b } => {
            let w_t = params
                .get(w)
                .cloned()
                .ok_or_else(|| EvalError::UndefinedVariable(w.clone()))?;
            let b_t = params
                .get(b)
                .cloned()
                .ok_or_else(|| EvalError::UndefinedVariable(b.clone()))?;
            let xw = x.matmul(&w_t);
            // Broadcast b ([1, out]) to [n, out] via ones([n, 1]) @ b,
            // mirroring apply_model's eager broadcast recipe so the
            // tape graph matches the hand-rolled form exactly.
            let n = xw.value().shape().dims()[0];
            let ones_arr = DenseArray::new(Shape::new(vec![n, 1]), vec![1.0; n])?;
            let ones_t = Tensor::leaf(Rc::clone(tape), ones_arr, false);
            let b_broadcast = ones_t.matmul(&b_t);
            Ok(xw.add(&b_broadcast))
        }
        ModelSpec::Chain(children) => {
            let mut cur = x;
            for child in children {
                cur = apply_model_tape(child, cur, tape, params)?;
            }
            Ok(cur)
        }
        ModelSpec::Activation(kind) => Ok(match kind {
            ActKind::Tanh => x.tanh(),
            ActKind::Relu => x.relu(),
            ActKind::Softmax => x.softmax(),
        }),
        ModelSpec::Residual(_) | ModelSpec::RmsNorm { .. } | ModelSpec::Attention { .. } => Err(
            EvalError::Unsupported(
                "grad: apply() through residual/rms_norm/attention is not yet supported; \
                 inline those layers in the loss expression for now"
                    .into(),
            ),
        ),
    }
}

